import{_ as t,o,c as a,a2 as i}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"ブラウザのタイミング (Browser Timings)","description":"","frontmatter":{},"headers":[],"relativePath":"ja/configuration/browser-timings.md","filePath":"ja/configuration/browser-timings.md"}'),r={name:"ja/configuration/browser-timings.md"};function n(c,e,s,d,m,p){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="ブラウザのタイミング-browser-timings" tabindex="-1"><i class="ph ph-clock-countdown"></i> ブラウザのタイミング (Browser Timings) <a class="header-anchor" href="#ブラウザのタイミング-browser-timings" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-clock-countdown&quot;&gt;&lt;/i&gt; ブラウザのタイミング (Browser Timings)&quot;">​</a></h1><p>このページでは、<code>Application.targetFrameRate</code> パラメータに関連する WebGL アーキテクチャの技術的な制限について詳しく説明します。</p><p>Unity プロジェクトを WebGL 用にコンパイルする場合、<code>Application.targetFrameRate</code> パラメータは、エンジンの内部フレーム制限を変更するだけでなく、メインループが実行される<strong>ベースとなるブラウザ API</strong>も変更します。</p><h2 id="無制限-uncapped-requestanimationframe" tabindex="-1">無制限 (Uncapped) (requestAnimationFrame) <a class="header-anchor" href="#無制限-uncapped-requestanimationframe" aria-label="Permalink to &quot;無制限 (Uncapped) (requestAnimationFrame)&quot;">​</a></h2><p>フレームレートの制限を解除すると（Unity のバージョンに応じて <code>Application.targetFrameRate</code> を <code>-1</code> または <code>0</code> に設定）、Emscripten コンパイラは Unity のメインループをブラウザ API である <code>window.requestAnimationFrame</code> に直接接続します。</p><ul><li><strong>利点:</strong> これは、Web 上で最もネイティブで、スムーズで、正確なレンダリング方法です。ブラウザは、この呼び出しをモニターの画面リフレッシュレート (VSync) と自動的に同期します。</li><li><strong>分析:</strong> <code>cpuMainThreadFrameTime</code> メトリクス（WebAP によって読み取られる）は、CPU が物理演算とスクリプトの計算に費やした<strong>実際の時間</strong>を反映するようになります。</li></ul><h2 id="人為的な制限-settimeout" tabindex="-1">人為的な制限 (setTimeout) <a class="header-anchor" href="#人為的な制限-settimeout" aria-label="Permalink to &quot;人為的な制限 (setTimeout)&quot;">​</a></h2><p>特定のフレームレートを厳格に課した場合（例：<code>Application.targetFrameRate = 30</code>）、Emscripten は <code>requestAnimationFrame</code> の使用を余儀なく放棄します。代わりに、<code>setTimeout()</code> API、または複雑な内部タイマーの組み合わせを利用して、ループを人為的に遅らせます。</p><div class="warning custom-block"><p class="custom-block-title">CPU メトリクスの歪み (Emscriptenの罠)</p><p>人工的なタイマーは、CPU 時間を測定する際に巨大な不一致とエラーを引き起こします。プロセッサはゲームロジックのすべての計算をわずか 5ms という超高速で完了し、アイドル状態に入ったとしても、<code>setTimeout</code> タイマーが切れるまで <code>WaitForEndOfFrame</code> コルーチンは再開されません。</p><p><strong>結果:</strong> <code>FrameTimingManager</code> は、この待機時間を CPU タイミング内に記録します。プロファイラー（および WebAP のトラッカー）は、プロセッサが機能的にアイドル状態であり、フレームが単にブラウザタイマーを待っているだけであるにもかかわらず、<em>CPU ボトルネック</em> が発生していると結論付けます。</p></div><h2 id="正しい設定戦略" tabindex="-1">正しい設定戦略 <a class="header-anchor" href="#正しい設定戦略" aria-label="Permalink to &quot;正しい設定戦略&quot;">​</a></h2><p>Web Adaptive Performance がブラウザで最適に機能するためには：</p><ol><li><strong><code>Application.targetFrameRate</code> を使用しないでください</strong>。<code>-1</code>（無制限）のままにします。</li><li>プラグイン設定内で目的の FPS を指定します（<code>Target Min FPS = 60</code>）。WebAP はこの値を厳格な制限としてではなく、レンダリング品質を決定するためのベースラインとして利用します。</li></ol>',12)])])}const g=t(r,[["render",n]]);export{u as __pageData,g as default};
